def same_function_implementation_check(node):
    function_names = set()
    visited_nodes = set()
    def check_node(node):
        if node.get('name') in function_names:
            return False
        if node['node_type'] == 'FunctionDef' and node not in visited_nodes:
            function_names.add(node['name'])
            visited_nodes.add(node)
            body = node['body']
            for child_node in body:
                check_node(child_node)
            return True
    root = node['node']
    return check_node(root)
